BEGIN
    DECLARE v_recent_challans INT DEFAULT 0;
    DECLARE v_plate_no VARCHAR(20);


    SELECT plate_no INTO v_plate_no 
    FROM VIOLATION_EVENTS 
    WHERE event_id = NEW.event_id;



    IF v_plate_no IS NOT NULL AND v_plate_no <> '' THEN
        SELECT COUNT(*) INTO v_recent_challans
        FROM CHALLANS c
        JOIN VIOLATION_EVENTS ve ON c.event_id = ve.event_id
        WHERE ve.plate_no = v_plate_no
          AND c.issue_date >= DATE_SUB(CURDATE(), INTERVAL 30 DAY)
          AND c.payment_status IN ('Unpaid', 'Paid', 'Overdue');


        IF v_recent_challans >= 3 THEN
            SET NEW.total_amount = NEW.total_amount * 2;
        END IF;
    END IF;
END

BEGIN
    INSERT INTO CHALLANS_HISTORY (
        challan_id, event_id, citizen_id, badge_no,
        total_amount, payment_status, issue_date, due_date,
        paid_at, transaction_ref,
        valid_from, valid_to, operation_type, changed_by
    ) VALUES (
        OLD.challan_id, OLD.event_id, OLD.citizen_id, OLD.badge_no,
        OLD.total_amount, OLD.payment_status, OLD.issue_date, OLD.due_date,
        OLD.paid_at, OLD.transaction_ref,
        OLD.valid_from, NOW(), 'UPDATE', 'SYSTEM'
    );

    SET NEW.valid_from = NOW();
    SET NEW.valid_to   = '9999-12-31 23:59:59';
END

BEGIN

    INSERT INTO CITIZENS_HISTORY (
        citizen_id, full_name, email, phone_no,
        trust_score, reward_points, account_status,
        valid_from, valid_to, operation_type, changed_by
    ) VALUES (
        OLD.citizen_id, OLD.full_name, OLD.email, OLD.phone_no,
        OLD.trust_score, OLD.reward_points, OLD.account_status,
        OLD.valid_from, NOW(), 'UPDATE', 'SYSTEM'
    );


    SET NEW.valid_from = NOW();
    SET NEW.valid_to   = '9999-12-31 23:59:59';


    IF NEW.trust_score <= 0 AND OLD.account_status = 'Active' THEN
        SET NEW.account_status = 'Suspended';
    END IF;
END

BEGIN
    DECLARE v_rejection_count INT DEFAULT 0;
    DECLARE v_total_rejections INT DEFAULT 0;
    DECLARE v_trust INT DEFAULT 0;
    IF OLD.status <> NEW.status THEN
        IF NEW.status = 'Verified' OR NEW.status = 'Challan Issued' THEN
            UPDATE CITIZENS
            SET trust_score = LEAST(trust_score + 10, 100),
                reward_points = reward_points + 5,
                consecutive_rejections = 0
            WHERE citizen_id = NEW.citizen_id;
            INSERT INTO NOTIFICATIONS (citizen_id, notif_type, message)
            VALUES (NEW.citizen_id, 'Report Verified',
                CONCAT('✅ Report #', NEW.report_id, ' verified! Trust +10, Points +5.'));
        ELSEIF NEW.status = 'Rejected' THEN
            SELECT consecutive_rejections, total_rejections
            INTO v_rejection_count, v_total_rejections
            FROM CITIZENS WHERE citizen_id = NEW.citizen_id;
            SET v_rejection_count = v_rejection_count + 1;
            SET v_total_rejections = v_total_rejections + 1;
            UPDATE CITIZENS
            SET trust_score = GREATEST(trust_score - 10, 0),
                consecutive_rejections = v_rejection_count,
                total_rejections = v_total_rejections
            WHERE citizen_id = NEW.citizen_id;
            SELECT trust_score INTO v_trust FROM CITIZENS WHERE citizen_id = NEW.citizen_id;
            IF v_trust <= 0 THEN
                UPDATE CITIZENS SET account_status = 'Suspended'
                WHERE citizen_id = NEW.citizen_id AND account_status = 'Active';
            END IF;
            INSERT INTO NOTIFICATIONS (citizen_id, notif_type, message)
            VALUES (NEW.citizen_id, 'Report Rejected',
                CONCAT('❌ Report #', NEW.report_id, ' rejected. Trust -10. Count: ', v_rejection_count));
        END IF;
    END IF;
END
